    99	        // fast path for single channel trackers. We only go with the fast path
   100	        // for new checkpoints, otherwise we might met with the case that
   101	        // 1. Received barrier from channel 0 (2 in total) and start a new checkpoint.
   102	        // 2. Received EndOfPartition from channel 0.
   103	        // 3. Received barrier from channel 1.
   104	        // In this case we should finish the existing pending checkpoint.
   105	        if (barrierId > latestPendingCheckpointID && numOpenChannels == 1) {
   106	            markAlignmentStartAndEnd(barrierId, receivedBarrier.getTimestamp());
   107	            notifyCheckpoint(receivedBarrier);
   108	            return;
   109	        }
   110	
   111	        // general path for multiple input channels
   112	        if (LOG.isDebugEnabled()) {
   113	            LOG.debug("Received barrier for checkpoint {} from channel {}", barrierId, channelInfo);
   114	        }
   115	
   116	        // find the checkpoint barrier in the queue of pending barriers
   117	        CheckpointBarrierCount barrierCount = null;
