   713	                asyncCheckpointRunnable.getCheckpointId(), asyncCheckpointRunnable);
   714	
   715	        // we are transferring ownership over snapshotInProgressList for cleanup to the thread,
   716	        // active on submit
   717	        asyncOperationsThreadPool.execute(asyncCheckpointRunnable);
   718	    }
   719	
   720	    private Consumer<AsyncCheckpointRunnable> unregisterConsumer() {
   721	        return asyncCheckpointRunnable ->
   722	                unregisterAsyncCheckpointRunnable(asyncCheckpointRunnable.getCheckpointId());
   723	    }
