   725	    private boolean takeSnapshotSync(
   726	            Map<OperatorID, OperatorSnapshotFutures> operatorSnapshotsInProgress,
   727	            CheckpointMetaData checkpointMetaData,
   728	            CheckpointMetricsBuilder checkpointMetrics,
   729	            CheckpointOptions checkpointOptions,
   730	            OperatorChain<?, ?> operatorChain,
   731	            Supplier<Boolean> isRunning)
   732	            throws Exception {
   733	
   734	        checkState(
   735	                !operatorChain.isClosed(),
   736	                "OperatorChain and Task should never be closed at this point");
   737	
   738	        long checkpointId = checkpointMetaData.getCheckpointId();
   739	        long started = System.nanoTime();
   740	
   741	        ChannelStateWriteResult channelStateWriteResult =
   742	                checkpointOptions.needsChannelState()
   743	                        ? channelStateWriter.getAndRemoveWriteResult(checkpointId)
   744	                        : ChannelStateWriteResult.EMPTY;
   745	
   746	        CheckpointStreamFactory storage =
   747	                checkpointStorage.resolveCheckpointStorageLocation(
   748	                        checkpointId, checkpointOptions.getTargetLocation());
   749	        storage = applyFileMergingCheckpoint(storage, checkpointOptions);
   750	
   751	        try {
   752	            operatorChain.snapshotState(
   753	                    operatorSnapshotsInProgress,
   754	                    checkpointMetaData,
   755	                    checkpointOptions,
   756	                    isRunning,
   757	                    channelStateWriteResult,
   758	                    storage);
   759	
   760	        } finally {
   761	            checkpointStorage.clearCacheFor(checkpointId);
   762	        }
   763	
   764	        checkpointMetrics.setSyncDurationMillis((System.nanoTime() - started) / 1_000_000);
   765	
   766	        LOG.debug(
   767	                "{} - finished synchronous part of checkpoint {}. Alignment duration: {} ms, snapshot duration {} ms, is unaligned checkpoint : {}",
   768	                taskName,
   769	                checkpointId,
   770	                checkpointMetrics.getAlignmentDurationNanosOrDefault() / 1_000_000,
   771	                checkpointMetrics.getSyncDurationMillis(),
   772	                checkpointOptions.isUnalignedCheckpoint());
   773	
   774	        return true;
   775	    }
   776	
   777	    private CheckpointStreamFactory applyFileMergingCheckpoint(
   778	            CheckpointStreamFactory storage, CheckpointOptions checkpointOptions) {
   779	        if (storage instanceof FsMergingCheckpointStorageLocation
   780	                && checkpointOptions.getCheckpointType().isSavepoint()) {
   781	            // fall back to non-fileMerging if it is a savepoint
   782	            return ((FsMergingCheckpointStorageLocation) storage).toNonFileMerging();
   783	        } else {
   784	            return storage;
   785	        }
   786	    }
